// Generated by OrchestKit Claude Plugin
// Created: 2026-04-27

/**
 * Expect Snapshot Recorder (M125 #6)
 *
 * After /ork:expect completes, persist the ARIA tree that the run captured to
 * the per-project snapshot store keyed by (route, parentCommit). On subsequent
 * runs, /ork:expect can diff against the last green snapshot for the same route
 * to surface UI regressions.
 *
 * Storage: .claude/state/expect-snapshots/<route-slug>/<parent-commit>.json
 *   (file-based; the memory MCP is optional and not required for this feature)
 *
 * Fires on: PostToolUse Skill where tool_input.skill === 'expect'.
 * Skips on: missing aria_snapshot in tool_output, or expect didn't pass.
 */

import { mkdirSync, writeFileSync, readdirSync } from 'node:fs';
import { execFileSync } from 'node:child_process';
import { join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputWithContext } from '../../lib/common.js';
import { NOOP_CTX } from '../../lib/context.js';
import { getProjectDir } from '../../lib/env.js';

const SNAPSHOT_DIR = '.claude/state/expect-snapshots';

function routeToSlug(route: string): string {
  return route
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '') || 'root';
}

function parentCommit(projectDir: string): string | null {
  try {
    return execFileSync('git', ['rev-parse', 'HEAD~1'], {
      cwd: projectDir,
      stdio: ['ignore', 'pipe', 'ignore'],
      encoding: 'utf8',
      timeout: 2000,
    }).trim();
  } catch {
    return null;
  }
}

interface SnapshotEnvelope {
  route: string;
  parentCommit: string | null;
  capturedAt: string;
  ariaSummary: string;
}

export async function expectSnapshotRecorder(
  input: HookInput,
  ctx: HookContext = NOOP_CTX
): Promise<HookResult> {
  if (input.tool_name !== 'Skill') return outputSilentSuccess();

  const skillName = (input.tool_input as Record<string, unknown>)?.skill;
  if (skillName !== 'expect') return outputSilentSuccess();

  const output = String(input.tool_output ?? '');
  if (!output.includes('RUN_COMPLETED|passed')) return outputSilentSuccess();

  // Look for the route + ARIA blob the skill emits.
  // Convention: lines tagged with `ROUTE|<route>` and `ARIA|<json>` in tool_output.
  const routeMatch = output.match(/ROUTE\|([^\n|]+)/);
  const ariaMatch = output.match(/ARIA\|(.+)/);
  if (!routeMatch || !ariaMatch) {
    ctx.log('expect-snapshot-recorder', 'No ROUTE / ARIA tags in expect output — skipping snapshot');
    return outputSilentSuccess();
  }

  const route = routeMatch[1].trim();
  const ariaSummary = ariaMatch[1].trim().slice(0, 8000); // cap at 8k to avoid runaway state

  const projectDir = getProjectDir();
  const slug = routeToSlug(route);
  const parent = parentCommit(projectDir);
  if (!parent) {
    ctx.log('expect-snapshot-recorder', 'Could not resolve parent commit — skipping');
    return outputSilentSuccess();
  }

  const dir = join(projectDir, SNAPSHOT_DIR, slug);
  mkdirSync(dir, { recursive: true });
  const filePath = join(dir, `${parent}.json`);

  const envelope: SnapshotEnvelope = {
    route,
    parentCommit: parent,
    capturedAt: new Date().toISOString(),
    ariaSummary,
  };
  writeFileSync(filePath, JSON.stringify(envelope, null, 2) + '\n');

  // Compare against the most recent prior snapshot for this route (if any).
  let prior: { commit: string; size: number } | null = null;
  try {
    const entries = readdirSync(dir).filter((f) => f.endsWith('.json') && !f.startsWith(parent));
    if (entries.length > 0) {
      // Pick lexicographically latest (commits look random-ish but recent file mtime dominates in practice).
      const last = entries.sort().slice(-1)[0];
      prior = { commit: last.replace(/\.json$/, ''), size: ariaSummary.length };
    }
  } catch {
    // ignore — fresh snapshot store
  }

  if (prior) {
    return outputWithContext(
      `ARIA snapshot recorded: route=${route} commit=${parent.slice(0, 8)} ` +
        `(prior: ${prior.commit.slice(0, 8)}). Run \`/ork:expect ${route} --diff\` ` +
        `to compare semantic structure.`
    );
  }
  return outputWithContext(
    `ARIA snapshot recorded: route=${route} commit=${parent.slice(0, 8)}. ` +
      `First snapshot for this route — future runs will diff against it.`
  );
}

export default expectSnapshotRecorder;
